module top_module(
    A,
    B,
    C,
    D,
    Y
);// Module ports
    input  A;
    input  B;
    input  C;
    input  D;
    output Y;

    // Local signals
    wire or0_in;
    wire and1_out;
    wire and2_out;

    // AND gates
    and and0 (or0_in, A, B);
    and and1 (and1_out, C, D);
    and and2 (Y, or0_in, and1_out);

endmodule
